import { useState, useEffect, useRef } from "react";

// ─── CONFIG ────────────────────────────────────────────────────
const NOME_APP       = "Fabiana Bolos";
const ADMIN_PASS     = "Leo";
const PIN_MASTER     = "Leo";
const DEV_PASS       = "dev2026";
const PIX_KEY        = "31999154485";
const WHATSAPP       = "5531999154485";
const MAX_ATTEMPTS   = 5;
const LOCK_MS        = 120_000;
const AUTO_LOGOUT_MS = 15 * 60 * 1000;
const SOFT_LOCK_DAYS = 5;
const pk = "#E91E8C", pkD = "#C2185B", pkL = "#FFF0F8";

const DEFAULT_CFG = {
  prazoMinHoras: 48, adicionalGourmet: 20, webhookUrl: "", licenseExpiry: "2027-12-31",
  licenseCheckUrl: "", datasTravadas: [], dominiosAutorizados: [], coresPreset: "confeitaria",
  regioes: [
    { id: 1, nome: "Retirada no local",    taxa: 0, isRetirada: true  },
    { id: 2, nome: "Entrega (A combinar)", taxa: 0, isRetirada: false },
  ],
};

// ─── OBFUSCAÇÃO DE DADOS SENSÍVEIS ────────────────────────────
const obf      = (s) => { try { return btoa(encodeURIComponent(s || "")); } catch { return s || ""; } };
const deobf    = (s) => { try { return decodeURIComponent(atob(s || "")); } catch { return s || ""; } };
const obfClt   = (c) => c ? { ...c, telefone: obf(c.telefone), aniversario: obf(c.aniversario || "") } : c;
const deobfClt = (c) => c ? { ...c, telefone: deobf(c.telefone), aniversario: deobf(c.aniversario || "") } : c;

// ─── STORAGE ──────────────────────────────────────────────────
const LS = {
  get:   (k) => { try { const v = localStorage.getItem(k); return v ? JSON.parse(v) : null; } catch { return null; } },
  set:   (k, v) => { try { localStorage.setItem(k, JSON.stringify(v)); return true; } catch { return false; } },
  del:   (k) => { try { localStorage.removeItem(k); } catch {} },
  check: () => { try { localStorage.setItem("_hc", "1"); return localStorage.getItem("_hc") === "1"; } catch { return false; } },
  usage: () => {
    try {
      let t = 0; const items = [];
      for (let i = 0; i < localStorage.length; i++) {
        const k = localStorage.key(i);
        if (k?.startsWith("fab_")) {
          const sz = (localStorage.getItem(k) || "").length * 2;
          t += sz;
          items.push({ k, sz: (sz / 1024).toFixed(1) + "KB" });
        }
      }
      return { totalKB: (t / 1024).toFixed(1), items };
    } catch { return { totalKB: "?", items: [] }; }
  },
};

// ─── CARDÁPIO ─────────────────────────────────────────────────
const TIPOS_BASE = [
  { id: "chantilly",   nome: "Bolo Chantilly",        desc: "A partir de R$ 110",    fotoUrl: "" },
  { id: "palitinhos",  nome: "Palitinhos de Chocolate",desc: "A partir de R$ 130",    fotoUrl: "" },
  { id: "chocolatudo", nome: "Bolo Chocolatudo",       desc: "A partir de R$ 175",    fotoUrl: "" },
  { id: "bento",       nome: "Bentô Cake",             desc: "R$ 50 – R$ 55",         fotoUrl: "" },
  { id: "docinhos",    nome: "Docinhos",               desc: "A partir de R$ 45/50 un",fotoUrl: "" },
];

const PRECOS = {
  chantilly:   { redondo: { 12:110,20:165,30:195,40:220,60:280,100:330 }, retangular: { 25:185,50:260,80:300,100:350,120:380 } },
  palitinhos:  { redondo: { 12:130,20:185,30:220,40:240,60:310,100:370 }, retangular: { 25:200,50:260,80:330,100:390,120:420 } },
  chocolatudo: { redondo: { 12:175,20:230,30:295,60:360 } },
  bento:       { tradicional: 50, gourmet: 55 },
  docinhos:    { tradicional: { 50:45,100:90 }, gourmet: { 50:55,100:110 } },
};

const MASSAS   = ["Baunilha", "Chocolate"];
const R_TRAD   = ["Brigadeiro Preto","Brigadeiro Branco","Beijinho de Coco","Bicho de Pé","Churros","Doce de Leite","Doce de Leite c/ Chocolate","Mousse de Morango","Mousse de Maracujá","Mousse de Limão","Ninho","Prestígio (2 recheios)"];
const R_GOUR   = ["Abacaxi","Ameixa","Creme de Nutella","Ganache Choc. Preto","Ganache Choc. Branco","Mousse de Chocolate","Nutella","Nozes","Ninho","Ninho c/ Morango","Pêssego","Romeu e Julieta"];
const R_BENTO_T= ["Brigadeiro Preto","Brigadeiro Branco","Beijinho de Coco","Doce de Leite","Mousse de Morango","Mousse de Maracujá","Ninho","Ninho c/ Morango"];
const R_BENTO_G= ["Nutella","Ninho com Nutella"];
const S_DOC_T  = ["Beijinho de Coco","Brigadeiro","Brigadeiro Branco","Cajuzinho","Ele e Ela","Olho de Sogra","Ninho","Abacaxi c/ Coco","Maracujá c/ Coco","Morango c/ Coco","Limão c/ Coco"];
const S_DOC_G  = ["Ninho com Nutella","Churros"];
const ALL_G    = [...R_GOUR, ...R_BENTO_G];

// ─── STATUS ÚNICO ─────────────────────────────────────────────
const STATUS_UNICO = [
  "Aguardando Caução",
  "Confirmado",
  "Em Produção",
  "Pronto para Entrega/Retirada",
  "Finalizado",
  "Cancelado",
];

const STATUS_META = {
  "Aguardando Caução":            { bg:"#FFF7ED", text:"#C2410C", brd:"#FED7AA", em:"⏳" },
  "Confirmado":                   { bg:"#F0FDF4", text:"#15803D", brd:"#BBF7D0", em:"✅" },
  "Em Produção":                  { bg:"#FFFBEB", text:"#B45309", brd:"#FDE68A", em:"👩‍🍳" },
  "Pronto para Entrega/Retirada": { bg:"#FAF5FF", text:"#7E22CE", brd:"#E9D5FF", em:"🎂" },
  "Finalizado":                   { bg:"#F1F5F9", text:"#475569", brd:"#CBD5E1", em:"🚀" },
  "Cancelado":                    { bg:"#FEF2F2", text:"#DC2626", brd:"#FECACA", em:"❌" },
};

const STATUS_LEGACY_MAP = {
  "aguardando caução": "Aguardando Caução",
  "confirmado":        "Confirmado",
  "em preparo":        "Em Produção",
  "pronto":            "Pronto para Entrega/Retirada",
  "entregue":          "Finalizado",
  "cancelado":         "Cancelado",
};

// ─── UPSELL ───────────────────────────────────────────────────
const UPSELL = [
  { id:"topper",    nome:"🎂 Topo de Bolo",    desc:"Personalizado",   preco: 18 },
  { id:"docinhos50",nome:"🍬 Docinhos Trad.",   desc:"50 unidades",     preco: 45 },
  { id:"bento_ex",  nome:"🎁 Bentô Cake extra", desc:"Mini bolo 10cm",  preco: 50 },
];
const UPSELL_PRECOS = Object.fromEntries(UPSELL.map(u => [u.id, u.preco]));
const PRECOS_MESTRES = { cardapio: PRECOS, upsell: UPSELL_PRECOS };

// ─── HELPERS ──────────────────────────────────────────────────
const san   = (d) => JSON.parse(JSON.stringify(d));
const fmtR  = (v) => `R$ ${Number(v).toFixed(2).replace(".", ",")}`;
const fmtDt = (d) => { if (!d) return "—"; const [y, m, day] = d.split("-"); return `${day}/${m}/${y}`; };
const today = () => new Date().toISOString().split("T")[0];
const minDt = (h) => { const d = new Date(); d.setHours(d.getHours() + Number(h)); return d.toISOString().split("T")[0]; };
const maskPh = (v) => {
  let r = v.replace(/\D/g, "").slice(0, 11);
  if (r.length > 10) return r.replace(/^(\d\d)(\d{5})(\d{4})/, "($1) $2-$3");
  if (r.length > 6)  return r.replace(/^(\d\d)(\d{4})(\d{0,4})/, "($1) $2-$3");
  if (r.length > 2)  return r.replace(/^(\d\d)(\d{0,5})/, "($1) $2");
  return r;
};
const isMonday   = (s) => { const d = new Date(s + "T12:00:00"); return d.getDay() === 1; };
const isTravada  = (s, arr) => (arr || []).includes(s);
const validateDate = (s, cfg) => {
  if (!s) return { ok: false, msg: "" };
  if (s < minDt(cfg.prazoMinHoras))  return { ok: false, msg: `⏰ Prazo mínimo ${cfg.prazoMinHoras}h. Disponível a partir de ${fmtDt(minDt(cfg.prazoMinHoras))}` };
  if (isMonday(s))                   return { ok: false, msg: "❌ Não atendemos às segundas-feiras" };
  if (isTravada(s, cfg.datasTravadas)) return { ok: false, msg: "❌ Data bloqueada — indisponível" };
  return { ok: true, msg: "" };
};
const isSinalPago  = (status) => ["Confirmado","Em Produção","Pronto para Entrega/Retirada","Finalizado"].includes(status);
const calcPontos   = (cId, orders) => Math.floor(orders.filter(o => o.clienteId === cId && o.status !== "Cancelado").reduce((s, o) => s + Number(o.valor || 0), 0));

const calcItem = (it, gAdic = 0) => {
  if (!it.tipo) return null;
  if (it.tipo === "upsell") return null;
  let b = null;
  if      (it.tipo === "bento")    b = PRECOS.bento[it.bentoTipo ?? "tradicional"] ?? 50;
  else if (it.tipo === "docinhos") b = PRECOS.docinhos[it.subtipo ?? "tradicional"]?.[Number(it.quantidade ?? 50)] ?? null;
  else                             b = PRECOS[it.tipo]?.[it.formato ?? "redondo"]?.[Number(it.fatias)] ?? null;
  if (b === null) return null;
  const g = (ALL_G.includes(it.recheio1) ? 1 : 0) + (ALL_G.includes(it.recheio2) ? 1 : 0);
  return b + g * Number(gAdic);
};

const getPrecoItem = (item, adicionalGourmet = 0) => {
  if (!item || !item.tipo) return null;
  if (item.tipo === "upsell" && item.upsellId) return PRECOS_MESTRES.upsell[item.upsellId] ?? null;
  return calcItem(item, adicionalGourmet);
};

const sanitizeInput = (text) => {
  if (!text) return "";
  return String(text).replace(/[<>"'/]/g, "");
};

const gerarChecksumPedido = (pedido) => {
  if (!pedido) return "";
  const dados = [
    pedido.id || "", pedido.nome || "", pedido.telefone || "",
    pedido.entrega || "", pedido.valor || 0, pedido.caucao || 0,
    pedido.status || "", JSON.stringify(pedido.itens || []),
  ].join("|");
  let hash = 0;
  for (let i = 0; i < dados.length; i++) {
    const char = dados.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(16).toUpperCase().padStart(8, "0");
};

