        <div style={{ marginBottom:12 }}>
          <label style={{ fontSize:13,fontWeight:700 }}>Massa *</label>
          <div style={{ display:"flex",gap:8 }}>
            {MASSAS.map(m => <BtnO key={m} active={f.massa===m} ch={m} st={{ flex:1 }} onClick={() => F({ massa:m })} />)}
          </div>
        </div>
        <Slct label="1º Recheio *" value={f.recheio1} onChange={e => F({ recheio1:e.target.value })} options={<><option value="">Escolha</option><optgroup label="── Tradicionais">{rT.map(r => <option key={r} value={r}>{r}</option>)}</optgroup><optgroup label="── Gourmet ⭐">{rG.map(r => <option key={r} value={r}>{r}</option>)}</optgroup></>} />
        <Slct label="2º Recheio (opcional)" value={f.recheio2} onChange={e => F({ recheio2:e.target.value })} options={<><option value="">Nenhum</option><optgroup label="── Tradicionais">{rT.map(r => <option key={r} value={r}>{r}</option>)}</optgroup><optgroup label="── Gourmet ⭐">{rG.map(r => <option key={r} value={r}>{r}</option>)}</optgroup></>} />
      </>}
      {f.tipo && <Fld label="Obs. deste item" value={f.obs} onChange={e => F({ obs:e.target.value })} />}
      {preco != null && <div style={{ background:pkL,borderRadius:10,padding:"8px 14px",marginBottom:12,fontWeight:800,color:pk }}>💰 {fmtR(preco)}</div>}
      <div style={{ display:"flex",gap:8 }}>
        <BtnS ch="Cancelar" st={{ flex:1 }} onClick={onCancel} />
        <Btn ch={isEdit ? "💾 Salvar" : "✅ Adicionar"} st={{ flex:2,opacity:ok?1:.5 }} disabled={!ok} onClick={() => ok && onSave(san(f))} />
      </div>
    </div>} />
  );
}

// ─── CONFIGS PANEL ────────────────────────────────────────────
function ConfigsPanel({ cfg, onSave, tipos, onUpdateTipos }) {
  const [c, setC] = useState(san(cfg));
  const [saved, setSaved] = useState(false);
  const [prodSelect, setProdSelect] = useState("");
  const [uploadFile, setUploadFile] = useState(null);
  const C = (p) => setC(x => san({ ...x, ...p }));
  function save() { onSave(san(c)); setSaved(true); setTimeout(() => setSaved(false), 2000); }
  function handleUpload() {
    if (!uploadFile || !prodSelect) return;
    const url  = URL.createObjectURL(uploadFile);
    const novos = (tipos || TIPOS_BASE).map(t => t.id === prodSelect ? { ...t, fotoUrl: url } : t);
    onUpdateTipos(novos);
    LS.set("fab_tipos", novos);
    setUploadFile(null); setProdSelect("");
  }
  return (
    <div className="fu">
      <h3 style={{ fontSize:17,fontWeight:900,marginBottom:14 }}>⚙️ Configurações</h3>
      <Card ch={<>
        <div style={{ fontWeight:800,color:pk,marginBottom:10 }}>🖼️ Upload Imagem Produto</div>
        <Slct label="Produto" value={prodSelect} onChange={e => setProdSelect(e.target.value)} options={<><option value="">Selecione</option>{(tipos||TIPOS_BASE).map(t => <option key={t.id} value={t.id}>{t.nome}</option>)}</>} />
        <Fld label="Imagem"><input type="file" accept="image/*" onChange={e => setUploadFile(e.target.files?.[0] || null)} style={fs} /></Fld>
        <Btn ch="Fazer Upload" st={{ marginBottom:8 }} onClick={handleUpload} disabled={!uploadFile || !prodSelect} />
        {(tipos||TIPOS_BASE).find(t => t.id === prodSelect)?.fotoUrl
          ? <img src={(tipos||TIPOS_BASE).find(t => t.id === prodSelect)?.fotoUrl} style={{ width:60,height:40,objectFit:"cover",borderRadius:8 }} alt="" onError={e => { e.target.src=""; e.target.alt="foto expirada"; }} />
          : null
        }
        <div style={{ fontSize:10,color:"#888",marginTop:4 }}>⚠️ Fotos são temporárias (sessão).</div>
      </>} />
      <Btn ch={saved ? "✅ Salvo!" : "💾 Salvar Configurações"} st={{ background:saved?"#15803D":pk }} onClick={save} />
    </div>
  );
}

