// ─── KERNEL PANEL ─────────────────────────────────────────────
function KernelPanel({ orders, clients, cfg, maintenanceMode, onSetMaintenance, onSetLicense, onSetOrders, onSetClients, onSetCfg, onBack }) {
  const [tab,      setTab]      = useState("terminal");
  const [cmd,      setCmd]      = useState("");
  const [output,   setOutput]   = useState([{ type:"sys", text:"Sistema Fabiana Bolos v2.0 — Kernel ready. Digite 'help' para comandos." }]);
  const [licDate,  setLicDate]  = useState(cfg.licenseExpiry || "");
  const [licSaved, setLicSaved] = useState(false);
  const [confirmReset, setConfirmReset] = useState("");
  const termRef = useRef(null);

  useEffect(() => {
    if (termRef.current) termRef.current.scrollTop = termRef.current.scrollHeight;
  }, [output]);

  const runCmd = () => {
    const c   = cmd.trim();
    const cLo = c.toLowerCase();
    let result = "";
    let type   = "out";
    if (!c) return;
    if (cLo === "help") {
      result = [
        "Comandos disponíveis:",
        "  status           — visão geral do sistema",
        "  orders           — listar todos os pedidos (JSON)",
        "  orders:count     — total de pedidos por status",
        "  clients          — listar clientes (JSON)",
        "  clients:count    — total de clientes",
        "  storage          — uso do localStorage",
        "  maintenance on   — ativar modo manutenção",
        "  maintenance off  — desativar modo manutenção",
        "  license:show     — exibir data de expiração",
        "  purge:cancelled  — remover pedidos cancelados",
        "  clear            — limpar terminal",
      ].join("\n");
    } else if (cLo === "status") {
      const ag = orders.filter(o => o.status === "Aguardando Caução").length;
      result = `📊 STATUS SISTEMA\n  Pedidos total : ${orders.length}\n  Ag. Caução   : ${ag}\n  Clientes      : ${clients.length}\n  Licença       : ${cfg.licenseExpiry}\n  Manutenção    : ${maintenanceMode ? "ATIVA" : "desativa"}\n  Storage       : ${LS.usage().totalKB} KB`;
    } else if (cLo === "orders") {
      result = JSON.stringify(orders.map(o => ({ id:o.id, nome:o.nome, status:o.status, entrega:o.entrega, valor:o.valor })), null, 2);
    } else if (cLo === "orders:count") {
      const counts = {};
      STATUS_UNICO.forEach(s => { counts[s] = orders.filter(o => o.status === s).length; });
      result = Object.entries(counts).map(([s, n]) => `  ${s.padEnd(35)}: ${n}`).join("\n");
    } else if (cLo === "clients") {
      result = JSON.stringify(clients.map(c => ({ id:c.id, nome:c.nome, telefone:c.telefone })), null, 2);
    } else if (cLo === "clients:count") {
      result = `Total de clientes: ${clients.length}`;
    } else if (cLo === "storage") {
      const u = LS.usage();
      result = `Total: ${u.totalKB} KB\n` + u.items.map(i => `  ${i.k.padEnd(25)} ${i.sz}`).join("\n");
    } else if (cLo === "maintenance on") {
      onSetMaintenance(true);
      result = "✅ Modo manutenção ATIVADO";
      type = "ok";
    } else if (cLo === "maintenance off") {
      onSetMaintenance(false);
      result = "✅ Modo manutenção DESATIVADO";
      type = "ok";
    } else if (cLo === "license:show") {
      result = `Licença atual: ${cfg.licenseExpiry}`;
    } else if (cLo === "purge:cancelled") {
      const antes = orders.length;
      const filtrado = orders.filter(o => o.status !== "Cancelado");
      onSetOrders(filtrado);
      result = `✅ Removidos ${antes - filtrado.length} pedidos cancelados. Restam: ${filtrado.length}`;
      type = "ok";
    } else if (cLo === "clear") {
      setOutput([{ type:"sys", text:"Terminal limpo." }]);
      setCmd(""); return;
    } else {
      result = `❌ Comando não reconhecido: "${c}". Digite 'help'.`;
      type = "err";
    }
    setOutput(p => [...p, { type:"cmd", text:`> ${c}` }, { type, text:result }]);
    setCmd("");
  };

  const handleKeyDown = (e) => { if (e.key === "Enter") runCmd(); };

  const saveLicense = () => {
    if (!licDate) return;
    onSetLicense(licDate);
    setLicSaved(true);
    setTimeout(() => setLicSaved(false), 2000);
  };

  const storageUsage = LS.usage();

  const textColor = { sys:"#555", out:"#00ff88", ok:"#00ffaa", err:"#ff4444", cmd:"#ffff00" };

  return (
    <div style={{ fontFamily:"'Share Tech Mono',monospace",background:"#0a0a0a",minHeight:"100vh",color:"#00ff88" }}>
      <style>{CSS}</style>
      {/* Header */}
      <div style={{ background:"#111",borderBottom:"1px solid #00ff88",padding:"10px 16px",display:"flex",alignItems:"center",justifyContent:"space-between",position:"sticky",top:0,zIndex:30 }}>
        <div style={{ display:"flex",alignItems:"center",gap:10 }}>
          <button onClick={onBack} className="kernel-btn" style={{ padding:"4px 10px",fontSize:12 }}>← SAIR</button>
          <span style={{ color:"#00ff88",fontSize:14,fontWeight:700 }}>▣ KERNEL — {NOME_APP.toUpperCase()}</span>
        </div>
        <span style={{ color:"#333",fontSize:10 }}>{new Date().toLocaleString("pt-BR")}</span>
      </div>

      {/* Tabs */}
      <div style={{ display:"flex",background:"#0a0a0a",borderBottom:"1px solid #1a1a1a" }}>
        {[["terminal","⬛ Terminal"],["system","⚙ System"],["storage","💾 Storage"]].map(([v, l]) => (
          <button key={v} className={`kernel-tab ${tab===v?"active":""}`} onClick={() => setTab(v)}>{l}</button>
        ))}
      </div>

      <div style={{ padding:16,maxWidth:700,margin:"0 auto" }}>

        {/* ── TERMINAL TAB ── */}
        {tab === "terminal" && (
          <div>
            <div ref={termRef} style={{ background:"#000",border:"1px solid #1a1a1a",borderRadius:8,padding:14,height:380,overflowY:"auto",marginBottom:12 }}>
              {output.map((line, i) => (
                <div key={i} style={{ color:textColor[line.type]||"#00ff88",fontSize:12,lineHeight:1.6,whiteSpace:"pre-wrap",wordBreak:"break-all" }}>
                  {line.text}
                </div>
              ))}
            </div>
            <div style={{ display:"flex",gap:8 }}>
              <input
                className="kernel-input"
                value={cmd}
                onChange={e => setCmd(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Digite um comando..."
                autoFocus
              />
              <button className="kernel-btn" onClick={runCmd} style={{ whiteSpace:"nowrap",padding:"8px 16px" }}>RUN</button>
            </div>
            <div style={{ fontSize:10,color:"#333",marginTop:8 }}>
              Enter para executar · 'help' para listar comandos
            </div>
          </div>
        )}

        {/* ── SYSTEM TAB ── */}
        {tab === "system" && (
          <div>
            <div style={{ color:"#ffff00",fontSize:13,marginBottom:16 }}>⚙ CONFIGURAÇÕES DO SISTEMA</div>

            {/* Licença */}
            <div style={{ background:"#111",border:"1px solid #00ff88",borderRadius:8,padding:16,marginBottom:14 }}>
              <div style={{ color:"#00ff88",fontWeight:700,marginBottom:12,fontSize:13 }}>🔑 LICENÇA</div>
              <div style={{ color:"#555",fontSize:11,marginBottom:8 }}>Expiração atual: <span style={{ color:"#00ff88" }}>{cfg.licenseExpiry || "—"}</span></div>
              <label style={{ fontSize:11,color:"#888",display:"block",marginBottom:4 }}>NOVA DATA DE EXPIRAÇÃO:</label>
              <input
                type="date"
                value={licDate}
                min={today()}
                onChange={e => setLicDate(e.target.value)}
                style={{ ...fsDark, marginBottom:10 }}
              />
              <button
                className="kernel-btn"
                style={{ width:"100%",background:licSaved?"#00ff88":undefined,color:licSaved?"#0a0a0a":undefined }}
                onClick={saveLicense}
                disabled={!licDate}
              >
                {licSaved ? "✅ LICENÇA ATUALIZADA" : "ATUALIZAR LICENÇA →"}
              </button>
            </div>

            {/* Manutenção */}
            <div style={{ background:"#111",border:"1px solid #333",borderRadius:8,padding:16,marginBottom:14 }}>
              <div style={{ color:"#ffff00",fontWeight:700,marginBottom:10,fontSize:13 }}>🔧 MODO MANUTENÇÃO</div>
              <div style={{ display:"flex",gap:10 }}>
                <button className="kernel-btn" style={{ flex:1,background:maintenanceMode?"#ff4444":undefined,color:maintenanceMode?"#fff":undefined,borderColor:maintenanceMode?"#ff4444":undefined }} onClick={() => onSetMaintenance(true)}>ATIVAR</button>
                <button className="kernel-btn" style={{ flex:1,background:!maintenanceMode?"#00ff88":undefined,color:!maintenanceMode?"#0a0a0a":undefined,borderColor:!maintenanceMode?"#00ff88":undefined }} onClick={() => onSetMaintenance(false)}>DESATIVAR</button>
              </div>
              <div style={{ fontSize:10,color: maintenanceMode?"#ff4444":"#00ff88",marginTop:8 }}>
                Status: {maintenanceMode ? "🔴 ATIVO — loja bloqueada" : "🟢 NORMAL — loja aberta"}
              </div>
            </div>

            {/* Reset dados */}
            <div style={{ background:"#111",border:"1px solid #ff4444",borderRadius:8,padding:16 }}>
              <div style={{ color:"#ff4444",fontWeight:700,marginBottom:10,fontSize:13 }}>⚠ ZONA DE PERIGO</div>
              <div style={{ color:"#555",fontSize:11,marginBottom:10 }}>Para confirmar exclusão total, digite <span style={{ color:"#ff4444" }}>RESETAR TUDO</span> abaixo:</div>
              <input
                className="kernel-input"
                style={{ borderColor:"#ff4444",marginBottom:8 }}
                value={confirmReset}
                onChange={e => setConfirmReset(e.target.value)}
                placeholder="RESETAR TUDO"
              />
              <button
                className="kernel-btn"
                style={{ width:"100%",borderColor:"#ff4444",color:"#ff4444",opacity:confirmReset==="RESETAR TUDO"?1:.4 }}
                disabled={confirmReset !== "RESETAR TUDO"}
                onClick={() => {
                  if (confirmReset !== "RESETAR TUDO") return;
                  ["fab_orders","fab_clients","fab_session","fab_tipos"].forEach(k => LS.del(k));
                  onSetOrders([]);
                  onSetClients([]);
                  setConfirmReset("");
                  setOutput(p => [...p,{ type:"err",text:"⚠ DADOS RESETADOS" }]);
                  setTab("terminal");
                }}
              >
                EXECUTAR RESET TOTAL
              </button>
            </div>
          </div>
        )}

        {/* ── STORAGE TAB ── */}
        {tab === "storage" && (
          <div>
            <div style={{ color:"#ffff00",fontSize:13,marginBottom:16 }}>💾 USO DO ARMAZENAMENTO LOCAL</div>
            <div style={{ background:"#111",border:"1px solid #1a1a1a",borderRadius:8,padding:14,marginBottom:14 }}>
              <div style={{ display:"flex",justifyContent:"space-between",marginBottom:12,borderBottom:"1px solid #1a1a1a",paddingBottom:10 }}>
                <span style={{ color:"#888",fontSize:11 }}>TOTAL USADO:</span>
                <span style={{ color:"#00ff88",fontWeight:700 }}>{storageUsage.totalKB} KB</span>
              </div>
              {storageUsage.items.length === 0
                ? <div style={{ color:"#333",fontSize:12 }}>Nenhuma chave fab_ encontrada.</div>
                : storageUsage.items.map((item, i) => (
                    <div key={i} style={{ display:"flex",justifyContent:"space-between",padding:"5px 0",borderBottom:"1px solid #0f0f0f",fontSize:12 }}>
                      <span style={{ color:"#00ff88" }}>{item.k}</span>
                      <span style={{ color:"#555" }}>{item.sz}</span>
                    </div>
                  ))
              }
            </div>
            <div style={{ background:"#111",border:"1px solid #1a1a1a",borderRadius:8,padding:14 }}>
              <div style={{ color:"#888",fontSize:11,marginBottom:10 }}>RESUMO DE REGISTROS:</div>
              {[
                ["fab_orders",   `${orders.length} pedidos`],
                ["fab_clients",  `${clients.length} clientes`],
                ["fab_tipos",    `${TIPOS_BASE.length} produtos`],
              ].map(([k, v]) => (
                <div key={k} style={{ display:"flex",justifyContent:"space-between",padding:"5px 0",fontSize:12 }}>
                  <span style={{ color:"#555" }}>{k}</span>
                  <span style={{ color:"#00ff88" }}>{v}</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ─── PEDIDO DONE SCREEN ───────────────────────────────────────
function PedidoDoneScreen({ caucao, wppUrl, onClientArea, onHome, hasClient, total, saldo }) {
  const [copied, setCopied] = useState(false);
  const mensagem = total ? `Olá, seu pedido ficou no valor total de ${fmtR(total)}. Foi pago ${fmtR(caucao)} de entrada. SALDO A COBRAR: ${fmtR(saldo)}.` : "";
  return (
    <div style={{ background:"#FDF6FB",minHeight:"100vh" }}>
      <style>{CSS}</style>
      <div style={{ padding:"24px 18px",maxWidth:480,margin:"0 auto",textAlign:"center" }}>
        <div style={{ fontSize:56 }}>🎉</div>
        <h2>Pedido enviado!</h2>
        {caucao > 0 && (
          <div style={{ background:"#F0FDF4",border:"1.5px solid #BBF7D0",borderRadius:14,padding:16,marginBottom:14,textAlign:"left" }}>
            <div style={{ fontWeight:900,color:"#15803D" }}>PIX 🟢</div>
            <div>Caução (50%): <strong>{fmtR(caucao)}</strong></div>
            {total && <div>Total: <strong>{fmtR(total)}</strong></div>}
            {saldo > 0 && <div style={{ fontWeight:900,color:"#B45309",textTransform:"uppercase" }}>💳 SALDO A COBRAR: {fmtR(saldo)}</div>}
            <div style={{ background:"#fff",border:"1.5px solid #BBF7D0",borderRadius:10,padding:"10px 14px",display:"flex",justifyContent:"space-between",marginBottom:8 }}>
              <span>{PIX_KEY}</span>
              <button onClick={() => { navigator.clipboard?.writeText(PIX_KEY); setCopied(true); }} style={{ border:"1px solid #15803D",color:"#15803D",borderRadius:8,padding:"4px 10px" }}>{copied ? "✓ Copiado!" : "Copiar"}</button>
            </div>
          </div>
        )}
        {mensagem && <div style={{ background:"#FFFBEB",border:"1px solid #FDE68A",borderRadius:10,padding:12,marginBottom:14,textAlign:"left",fontWeight:700 }}>{mensagem}</div>}
        <a href={wppUrl} target="_blank" rel="noreferrer" style={{ display:"block",marginBottom:10,textDecoration:"none" }}>
          <Btn ch="💬 Enviar comprovante no WhatsApp" st={{ background:"#25D366" }} />
        </a>
        {hasClient && <Btn ch="Ver meus pedidos" st={{ background:pkD,marginBottom:8 }} onClick={onClientArea} />}
        <BtnS ch="Voltar ao início" onClick={onHome} />
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// APP PRINCIPAL
// ═══════════════════════════════════════════════════════════════
export default function App() {
  const [cfg,            setCfg]           = useState(() => LS.get("fab_cfg") ?? san(DEFAULT_CFG));
  const [orders,         setOrders]        = useState(() => (LS.get("fab_orders") ?? []).map(o => {
    if (!STATUS_UNICO.includes(o.status)) o.status = STATUS_LEGACY_MAP[o.status?.toLowerCase()] || "Aguardando Caução";
    if (!o.checksum) o.checksum = gerarChecksumPedido(o);
    return o;
  }));
  const [clients,        setClients]       = useState(() => (LS.get("fab_clients") ?? []).map(deobfClt));
  const [clientUser,     setClientUser]    = useState(() => { const s = LS.get("fab_session"); return s ? deobfClt(s) : null; });
  const [maintenanceMode,setMaintenanceMode]= useState(() => LS.get("fab_maintenance") ?? false);
  const [tipos,          setTipos]         = useState(() => LS.get("fab_tipos") ?? san(TIPOS_BASE));
  const TIPOS = (tipos && tipos.length) ? tipos : TIPOS_BASE;

  const [screen,         setScreen]        = useState("home");
  const [cart,           setCart]          = useState([]);
  const [cartPulse,      setCartPulse]     = useState(false);
  const [pedInfo,        setPedInfo]       = useState({ entrega:"",hora:"",obs:"",regiao:null,comprovante:"",enderecoEntrega:"" });
  const [editIdx,        setEditIdx]       = useState(null);
  const [addingIt,       setAddingIt]      = useState(false);
  const [doneData,       setDoneData]      = useState({ caucao:0,wppUrl:"",total:null,saldo:null });
  const [upsellOpen,     setUpsellOpen]    = useState(false);
  const [dateErr,        setDateErr]       = useState("");
  const [adminTab,       setAdminTab]      = useState("hoje");
  const [adminSrch,      setAdminSrch]     = useState("");
  const [adminFlt,       setAdminFlt]      = useState("todos");
  const [selOrdId,       setSelOrdId]      = useState(null);
  const [showClts,       setShowClts]      = useState(false);
  const [pinDlg,         setPinDlg]        = useState(null);
  const [labelOrd,       setLabelOrd]      = useState(null);
  const [lockedUntil,    setLockedUntil]   = useState(() => LS.get("fab_lockuntil") ?? 0);
  const [lockLeft,       setLockLeft]      = useState(0);
  const [remoteLicOk,    setRemoteLicOk]   = useState(null);

  const loginAttempts = useRef(0);
  const [clickCt,   setClickCt]   = useState(0);
  const clickTimer              = useRef(null);
  const lastActivity            = useRef(Date.now());
  const autoLogoutRef           = useRef(null);

  // ── Logo click: 5 cliques → admin, 7 cliques → kernel
  const handleLogoClick = () => {
    setClickCt(p => {
      const n = p + 1;
      if (n >= 7) { setScreen("kernel-login"); clearTimeout(clickTimer.current); return 0; }
      if (n === 5) setScreen("admin-login");
      return n;
    });
    clearTimeout(clickTimer.current);
    clickTimer.current = setTimeout(() => setClickCt(0), 3000);
  };

  const hoy = today();

  // ── Atualizar pedido
  const updateOrd = (id, patch) => setOrders(p => san(p.map(o => {
    if (o.id !== id) return o;
    const upd = { ...o, ...patch };
    upd.freteManual = Number(upd.freteManual || 0);
    const totalItens = upd.itens?.reduce((s, it) => s + (getPrecoItem(it, cfg.adicionalGourmet) ?? 0), 0) ?? 0;
    const totalFinal = totalItens + (Number(upd.regiao?.taxa || 0)) + upd.freteManual;
    upd.valor  = totalFinal || null;
    upd.caucao = totalFinal ? Math.ceil(totalFinal * .5) : null;
    upd.checksum = gerarChecksumPedido(upd);
    return upd;
  })));

  const removeOrd = (id) => setOrders(p => p.filter(o => o.id !== id));

  // ── Persistência
  useEffect(() => { LS.set("fab_cfg",          cfg);                            }, [cfg]);
  useEffect(() => { LS.set("fab_orders",        orders);                        }, [orders]);
  useEffect(() => { LS.set("fab_clients",       clients.map(obfClt));           }, [clients]);
  useEffect(() => { LS.set("fab_maintenance",   maintenanceMode);               }, [maintenanceMode]);
  useEffect(() => { LS.set("fab_tipos",         tipos);                         }, [tipos]);
  useEffect(() => { LS.set("fab_session",       clientUser ? obfClt(clientUser) : null); }, [clientUser]);

  // ── Lock timer
  useEffect(() => {
    if (!lockedUntil || Date.now() >= lockedUntil) return;
    const iv = setInterval(() => {
      const left = Math.ceil((lockedUntil - Date.now()) / 1000);
      setLockLeft(Math.max(0, left));
      if (left <= 0) { setLockedUntil(0); LS.set("fab_lockuntil", 0); loginAttempts.current = 0; clearInterval(iv); }
    }, 1000);
    return () => clearInterval(iv);
  }, [lockedUntil]);

  // ── Auto-logout admin
  useEffect(() => {
    if (screen !== "admin") return;
    const track = () => { lastActivity.current = Date.now(); };
    window.addEventListener("click",      track);
    window.addEventListener("touchstart", track);
    autoLogoutRef.current = setInterval(() => {
      if (Date.now() - lastActivity.current > AUTO_LOGOUT_MS) setScreen("home");
    }, 30000);
    return () => { clearInterval(autoLogoutRef.current); window.removeEventListener("click", track); window.removeEventListener("touchstart", track); };
  }, [screen]);

  // ── Remote license check
  useEffect(() => {
    if (!cfg.licenseCheckUrl) return;
    fetch(cfg.licenseCheckUrl).then(r => r.json()).then(d => { setRemoteLicOk(d.valid === true); }).catch(() => { setRemoteLicOk(null); });
  }, []);

  // ── Cart pulse
  useEffect(() => {
    if (cart.length > 0) { setCartPulse(true); const t = setTimeout(() => setCartPulse(false), 400); return () => clearTimeout(t); }
  }, [cart.length]);

  // ── PWA manifest
  useEffect(() => {
    try {
      if (!document.querySelector('link[rel="manifest"]')) {
        const mf   = { name:NOME_APP,short_name:"Fab Bolos",display:"standalone",background_color:"#FFF0F8",theme_color:"#E91E8C",start_url:"/" };
        const blob = new Blob([JSON.stringify(mf)], { type:"application/manifest+json" });
        const link = document.createElement("link"); link.rel="manifest"; link.href=URL.createObjectURL(blob);
        document.head.appendChild(link);
      }
    } catch {}
  }, []);

  const resetPed = () => { setCart([]); setPedInfo({ entrega:"",hora:"",obs:"",regiao:null,comprovante:"",enderecoEntrega:"" }); setEditIdx(null); setAddingIt(false); setDateErr(""); };

  // ── Domain check
  const domOk = (() => {
    const doms = cfg.dominiosAutorizados || [];
    if (!doms.length) return true;
    const h = window.location.hostname;
    return doms.some(d => h === d || h === "localhost" || h.endsWith("." + d));
  })();

  const daysLeft       = cfg.licenseExpiry ? Math.ceil((new Date(cfg.licenseExpiry) - new Date()) / (1000*60*60*24)) : 999;
  const softLockWarning= daysLeft > 0 && daysLeft <= SOFT_LOCK_DAYS;

  // ── Cart totals
  const cartTotal        = cart.reduce((s, it) => s + (getPrecoItem(it, cfg.adicionalGourmet) ?? 0), 0);
  const isRegiaoRetirada = pedInfo.regiao?.isRetirada ?? false;
  const taxaReg          = isRegiaoRetirada ? 0 : Number(pedInfo.regiao?.taxa || 0);
  const cartFinal        = cartTotal + taxaReg;
  const cartCaucao       = Math.ceil(cartFinal * .5);
  const cartSaldo        = cartFinal - cartCaucao;

  const selOrd = orders.find(o => o.id === selOrdId);

  // ── Listas filtradas
  const todayOrds = orders.filter(o => o.entrega === hoy).sort((a, b) => (a.hora||"").localeCompare(b.hora||""));
  const urgentes  = orders.filter(o => o.entrega <= hoy && o.status !== "Finalizado" && o.status !== "Cancelado").length;
  const semOrds   = orders.filter(o => {
    const d = new Date(o.entrega); const n = new Date(); n.setHours(0,0,0,0); const f = new Date(n); f.setDate(f.getDate() + 7);
    return d >= n && d <= f && o.status !== "Cancelado";
  });

  // ── Faturamento mensal (excluindo Cancelado e Aguardando Caução — ainda não confirmados)
  const mesAtual  = new Date().getMonth();
  const anoAtual  = new Date().getFullYear();
  const ordsMes   = orders.filter(o => {
    const d = new Date(o.entrega);
    return d.getMonth() === mesAtual && d.getFullYear() === anoAtual
      && o.status !== "Cancelado"
      && o.status !== "Aguardando Caução";
  });
  const totalMes  = ordsMes.reduce((s, o) => s + Number(o.valor || 0), 0);
  const totalMesFinalizado = orders.filter(o => {
    const d = new Date(o.entrega);
    return d.getMonth() === mesAtual && d.getFullYear() === anoAtual && o.status === "Finalizado";
  }).reduce((s, o) => s + Number(o.valor || 0), 0);

  // ── Filtros admin
  const allFilt  = orders.filter(o => {
    const ms = !adminSrch || o.nome?.toLowerCase().includes(adminSrch.toLowerCase()) || o.telefone?.includes(adminSrch);
    const mf = adminFlt === "todos" || o.status === adminFlt;
    return ms && mf;
  }).sort((a, b) => new Date(a.entrega) - new Date(b.entrega));
  const byDate   = {};
  allFilt.forEach(o => { if (!byDate[o.entrega]) byDate[o.entrega] = []; byDate[o.entrega].push(o); });
  const sortDates = Object.keys(byDate).sort();

  // ── Aniversariantes do mês
  const mesMes = new Date().getMonth() + 1;
  const aniversariantes = clients.filter(c => {
    const a = c.aniversario; if (!a) return false;
    return Number(a.split("-")[1]) === mesMes;
  });

  const repetirPedido = (order) => {
    if (!order?.itens) return;
    setCart(san(order.itens));
    setPedInfo({ entrega:"",hora:"",obs:"",regiao:null,comprovante:"",enderecoEntrega:order.endereco||"" });
    setScreen("pedido-cart");
  };

  const confirmarPedidoFinal = (extraItems = []) => {
    if (!LS.check()) return;
    if (cartTotal <= 0 && extraItems.length === 0) return alert("Adicione itens ao carrinho!");
    const upsellItems = extraItems.map(u => ({ tipo:"upsell",upsellId:u.id,nome:u.nome,desc:u.desc }));
    const allCart     = [...cart, ...upsellItems];
    const totalItens  = allCart.reduce((s, it) => s + (getPrecoItem(it, cfg.adicionalGourmet) ?? 0), 0);
    const totalFinal  = totalItens + taxaReg;
    const caucaoFinal = totalFinal ? Math.ceil(totalFinal * .5) : 0;
    const saldoFinal  = totalFinal ? totalFinal - caucaoFinal : 0;
    const nomeSan     = sanitizeInput(clientUser?.nome || "");
    const obsSan      = sanitizeInput(pedInfo.obs);
    const compSan     = sanitizeInput(pedInfo.comprovante);
    const enderecoSan = sanitizeInput(pedInfo.enderecoEntrega || clientUser?.endereco || "");
    const novoId      = Date.now() + Math.floor(Math.random() * 1000);
    const novo        = san({
      id: novoId,
      clienteId: clientUser?.id ?? null,
      nome: nomeSan,
      telefone: clientUser?.telefone ?? "",
      endereco: enderecoSan,
      entrega: pedInfo.entrega,
      hora: pedInfo.hora || "",
      regiao: pedInfo.regiao ?? null,
      obs: obsSan,
      comprovante: compSan || "",
      itens: allCart,
      valor: totalFinal || null,
      caucao: caucaoFinal || null,
      status: "Aguardando Caução",
      freteManual: 0,
      criadoEm: new Date().toISOString(),
    });
    novo.checksum = gerarChecksumPedido(novo);
    setOrders(p => san([...p, novo]));
    if (clientUser) setClients(p => san(p.map(c => c.id === clientUser.id ? { ...c, historico:[...(c.historico??[]),novo.id] } : c)));
    if (cfg.webhookUrl) try { fetch(cfg.webhookUrl, { method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(san(novo)) }); } catch {}
    const wppTxt = encodeURIComponent(`Olá! Pedido 🎂\n👤 ${nomeSan}\n📅 ${fmtDt(pedInfo.entrega)}\n💰 Total: ${totalFinal?fmtR(totalFinal):"?"}\n💳 Caução: ${fmtR(caucaoFinal)}\n📌 SALDO: ${fmtR(saldoFinal)}`);
    setDoneData({ caucao:caucaoFinal, wppUrl:`https://wa.me/${WHATSAPP}?text=${wppTxt}`, total:totalFinal, saldo:saldoFinal });
    resetPed();
    setScreen("pedido-done");
  };

  // ── Guardas de tela
  if (!LS.check()) return <div style={{ background:pkL,minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center" }}><style>{CSS}</style><div>🔧 Em manutenção</div></div>;
  if (!domOk)       return <DomainLockScreen />;

  if (screen === "admin-login")  return <AdminLoginScreen  onLogin={() => { loginAttempts.current=0; lastActivity.current=Date.now(); setScreen("admin"); }} onBack={() => setScreen("home")} lockedUntil={lockedUntil} lockLeft={lockLeft} />;
  if (screen === "kernel-login") return <KernelLoginScreen onLogin={() => setScreen("kernel")} onBack={() => setScreen("home")} lockedUntil={lockedUntil} lockLeft={lockLeft} />;
  if (screen === "kernel")       return <KernelPanel orders={orders} clients={clients} cfg={cfg} maintenanceMode={maintenanceMode} onSetMaintenance={setMaintenanceMode} onSetLicense={d => setCfg(c => san({ ...c, licenseExpiry:d }))} onSetOrders={v => setOrders(san(v))} onSetClients={v => setClients(san(v))} onSetCfg={v => setCfg(san(v))} onBack={() => setScreen("home")} />;

  const licExpired = (cfg.licenseExpiry && today() > cfg.licenseExpiry) && (remoteLicOk === false || remoteLicOk === null);
  if (licExpired && !["admin-login","admin"].includes(screen)) return <LicenseExpiredScreen expiry={cfg.licenseExpiry} />;

  if (screen === "client-login")    return <ClientLoginScreen    clients={clients} onLogin={c => { setClientUser(san(c)); setScreen("client-area"); }} onRegister={() => setScreen("client-register")} onBack={() => setScreen("home")} />;
  if (screen === "client-register") return <ClientRegisterScreen onSave={f => { const c = san({ id:Date.now(),...f,historico:[],endereco:"" }); setClients(p => san([...p,c])); setClientUser(c); setScreen("client-area"); }} onBack={() => setScreen("client-login")} />;
  if (screen === "pedido-done")     return <PedidoDoneScreen caucao={doneData.caucao} wppUrl={doneData.wppUrl} hasClient={!!clientUser} onClientArea={() => setScreen("client-area")} onHome={() => setScreen("home")} total={doneData.total} saldo={doneData.saldo} />;
  if (maintenanceMode && ["pedido-info","pedido-cart","pedido-confirm"].includes(screen)) return <MaintenanceScreen onAdmin={() => setScreen("admin-login")} />;

  // ── Modais globais (PIN, Label, Upsell)
  const globalModais = (<>
    {pinDlg    && <PinDlg msg={pinDlg.msg} onOk={() => { pinDlg.onOk(); setPinDlg(null); }} onCancel={() => setPinDlg(null)} />}
    {labelOrd  && <LabelModal order={labelOrd} cfg={cfg} tipos={TIPOS} onClose={() => setLabelOrd(null)} />}
    {upsellOpen && <UpsellModal onAdd={extras => { setUpsellOpen(false); confirmarPedidoFinal(extras); }} onSkip={() => { setUpsellOpen(false); confirmarPedidoFinal([]); }} />}
  </>);

  // ══════════════════════════════════════════════════════════════
  // ── HOME ──────────────────────────────────────────────────────
  if (screen === "home") return (
    <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
      <style>{CSS}</style>
      {globalModais}
      {softLockWarning && <div style={{ background:"#FFFBEB",borderBottom:"2px solid #FDE68A",padding:"8px 16px",textAlign:"center",fontSize:13,color:"#B45309",fontWeight:700 }}>⚠️ Licença expira em {daysLeft}d</div>}
      <header style={{ background:"#fff",borderBottom:`2px solid ${pkL}`,padding:"14px 18px",display:"flex",justifyContent:"space-between",alignItems:"center",position:"sticky",top:0,zIndex:30 }} className="no-print">
        <span style={{ fontSize:22,fontWeight:900,color:pk,fontFamily:"'Playfair Display',serif",cursor:"pointer" }} onClick={handleLogoClick}>{NOME_APP}</span>
        <div className={cartPulse ? "pulse" : ""} style={{ color:pk,padding:"7px 16px",borderRadius:20,fontWeight:800,border:`1px solid ${pkL}`,cursor:"pointer" }} onClick={() => cart.length > 0 ? setScreen("pedido-cart") : null}>
          🛒 {cart.length}
        </div>
      </header>
      <div style={{ padding:"20px 18px",maxWidth:450,margin:"0 auto" }} className="fu">
        <div style={{ background:"#fff",padding:24,borderRadius:24,marginBottom:18 }}>
          <div style={{ fontSize:12,color:"#C084B4",fontWeight:700 }}>Olá! 🌸</div>
          <h2 style={{ fontFamily:"'Playfair Display',serif",margin:"0 0 6px",fontSize:22 }}>{clientUser ? `Bem-vinda, ${clientUser.nome?.split(" ")[0]}!` : "Bem-vinda!"}</h2>
          {clientUser && <div style={{ fontSize:12,color:"#C084B4" }}>⭐ {calcPontos(clientUser.id, orders)} pontos</div>}
          <p style={{ fontSize:14,color:"#888" }}>{todayOrds.length} entrega{todayOrds.length !== 1 ? "s" : ""} hoje.</p>
        </div>
        {maintenanceMode && <Warn ch="🔧 Sistema em manutenção" />}
        <Btn ch="🎂 Fazer Pedido" onClick={() => { if (!clientUser) setScreen("client-login"); else setScreen("pedido-info"); }} st={{ marginBottom:12 }} disabled={maintenanceMode} />
        <BtnS ch={clientUser ? "👤 Minha Conta" : "👤 Entrar / Cadastrar"} st={{ marginBottom:12 }} onClick={() => clientUser ? setScreen("client-area") : setScreen("client-login")} />
      </div>
    </div>
  );

  // ── CLIENT AREA ───────────────────────────────────────────────
  if (screen === "client-area" && clientUser) {
    const meus  = orders.filter(o => o.clienteId === clientUser.id).sort((a, b) => new Date(b.criadoEm) - new Date(a.criadoEm));
    const pontos = calcPontos(clientUser.id, orders);
    return (
      <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
        <style>{CSS}</style>
        <div style={{ background:`linear-gradient(135deg,${pk},${pkD})`,padding:"20px 18px 28px" }}>
          <button onClick={() => setScreen("home")} style={{ background:"rgba(255,255,255,.2)",border:"none",color:"#fff",borderRadius:8,padding:"4px 10px",fontWeight:700,marginBottom:12 }}>← Voltar</button>
          <div style={{ color:"#fff" }}>
            <div style={{ fontSize:12,opacity:.8 }}>Bem-vinda! 🌸</div>
            <div style={{ fontFamily:"'Playfair Display',serif",fontSize:22,fontWeight:700 }}>{clientUser.nome}</div>
            <div style={{ fontSize:13,opacity:.8 }}>{clientUser.telefone}</div>
            {clientUser.aniversario && <div style={{ fontSize:12,opacity:.7 }}>🎂 {fmtDt(clientUser.aniversario)}</div>}
            <div style={{ fontSize:12,opacity:.8 }}>⭐ {pontos} pontos</div>
          </div>
        </div>
        <div style={{ padding:16,maxWidth:500,margin:"0 auto",marginTop:-12 }}>
          <Btn ch="🎂 Novo pedido" st={{ marginBottom:16 }} disabled={maintenanceMode} onClick={() => !maintenanceMode && setScreen("pedido-info")} />
          <h3 style={{ fontSize:16,fontWeight:900,marginBottom:12 }}>Meus pedidos ({meus.length})</h3>
          {meus.length === 0
            ? <div style={{ textAlign:"center",padding:"32px 0",color:"#C084B4" }}>📦 Nenhum pedido</div>
            : meus.map(o => {
                const saldo = (o.valor||0) - (o.caucao||0);
                return (
                  <div key={o.id} className="hov" style={{ background:"#fff",border:`1px solid ${pkL}`,borderLeft:`4px solid ${pk}`,borderRadius:14,padding:14,marginBottom:10 }}>
                    <div style={{ display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:6 }}>
                      <div style={{ fontSize:13,color:"#888" }}>📅 {fmtDt(o.entrega)}</div>
                      <Badge s={o.status} />
                    </div>
                    <StatusBar status={o.status} />
                    {o.itens?.slice(0, 2).map((it, i) => {
                      const nm = it.tipo === "upsell" ? it.nome : (TIPOS.find(t => t.id === it.tipo)?.nome);
                      return <div key={i} style={{ fontSize:13,color:"#444" }}>🎂 {nm}</div>;
                    })}
                    <div style={{ marginTop:6,fontWeight:800,color:pk }}>{o.valor ? fmtR(o.valor) : "Sob consulta"}</div>
                    {saldo != null && isSinalPago(o.status) && <div style={{ fontSize:12,color:"#B45309",fontWeight:700 }}>💳 SALDO: {fmtR(saldo)}</div>}
                    <button onClick={() => repetirPedido(o)} style={{ background:pkL,color:pk,border:"none",borderRadius:8,padding:"4px 10px",fontSize:11,fontWeight:700,marginTop:8 }}>🔄 Repetir</button>
                  </div>
                );
              })
          }
          <button onClick={() => { setClientUser(null); setScreen("home"); }} style={{ width:"100%",background:"none",border:"1.5px solid #E5D0EE",borderRadius:12,padding:11,fontWeight:700,color:"#9CA3AF",marginTop:8 }}>Sair</button>
        </div>
      </div>
    );
  }

  // ── PEDIDO INFO ───────────────────────────────────────────────
  if (screen === "pedido-info") return (
    <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
      <style>{CSS}</style>
      <Hdr title="📅 Dados do pedido" onBack={() => setScreen(clientUser ? "client-area" : "home")} />
      <div style={{ padding:18,maxWidth:500,margin:"0 auto" }} className="fu">
        <div style={{ marginBottom:12 }}>
          <label style={{ fontSize:13,fontWeight:700,color:"#6B4C7A",display:"block",marginBottom:4 }}>Data de entrega *</label>
          <input type="date" value={pedInfo.entrega} min={minDt(cfg.prazoMinHoras)} onChange={e => {
            const v = e.target.value;
            const r = validateDate(v, cfg);
            setDateErr(r.msg);
            setPedInfo(x => ({ ...x, entrega:r.ok ? v : "" }));
          }} style={{ ...fs, border:`1px solid ${dateErr ? "#DC2626" : "#E5D0EE"}` }} />
          {dateErr && <div style={{ color:"#DC2626",fontSize:12 }}>{dateErr}</div>}
          {!dateErr && pedInfo.entrega && <div style={{ color:"#15803D",fontSize:12 }}>✅ Data disponível</div>}
        </div>
        <Fld label="Horário"><input type="time" value={pedInfo.hora} onChange={e => setPedInfo(x => ({ ...x, hora:e.target.value }))} style={fs} /></Fld>
        {cfg.regioes.length > 0 && (
          <Slct label="Região / Entrega *" value={pedInfo.regiao?.id ?? ""} onChange={e => {
            const r = cfg.regioes.find(x => String(x.id) === e.target.value);
            setPedInfo(p => ({ ...p, regiao:r ?? null }));
          }} options={<>
            <option value="">Selecione</option>
            {cfg.regioes.map(r => <option key={r.id} value={r.id}>{r.nome}{!r.isRetirada && r.taxa > 0 ? ` (+${fmtR(r.taxa)})` : ""}</option>)}
          </>} />
        )}
        {!isRegiaoRetirada && pedInfo.regiao && (
          <Fld label="Endereço de Entrega *">
            <input placeholder="Rua, número, bairro..." value={pedInfo.enderecoEntrega} onChange={e => setPedInfo(x => ({ ...x, enderecoEntrega:e.target.value }))} style={fs} />
          </Fld>
        )}
        <Fld label="Observações" value={pedInfo.obs} onChange={e => setPedInfo(x => ({ ...x, obs:e.target.value }))} />
        <Btn ch="Montar meu pedido →"
          st={{ opacity:(pedInfo.entrega && !dateErr && pedInfo.regiao && (isRegiaoRetirada || !!pedInfo.enderecoEntrega)) ? 1 : .5 }}
          disabled={!pedInfo.entrega || !!dateErr || !pedInfo.regiao || (!isRegiaoRetirada && !pedInfo.enderecoEntrega)}
          onClick={() => setScreen("pedido-cart")}
        />
      </div>
    </div>
  );

  // ── CARRINHO ──────────────────────────────────────────────────
  if (screen === "pedido-cart") return (
    <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
      <style>{CSS}</style>
      <Hdr title="🛒 Carrinho" onBack={() => setScreen("pedido-info")} right={cart.length > 0 ? <span style={{ background:pk,color:"#fff",borderRadius:20,padding:"2px 10px",fontSize:13,fontWeight:800 }}>{cart.length}</span> : null} />
      <div style={{ padding:16,maxWidth:500,margin:"0 auto" }}>
        {cart.map((it, idx) => {
          const preco = getPrecoItem(it, cfg.adicionalGourmet);
          const isU   = it.tipo === "upsell";
          const nome  = isU ? it.nome : (TIPOS.find(t => t.id === it.tipo)?.nome);
          const prod  = TIPOS.find(t => t.id === it.tipo);
          return editIdx === idx
            ? <div key={idx} className="fu"><ItemBuilder init={it} isEdit gAdic={cfg.adicionalGourmet} tipos={TIPOS} onSave={u => { setCart(p => san(p.map((x, i) => i === idx ? u : x))); setEditIdx(null); }} onCancel={() => setEditIdx(null)} /></div>
            : (
              <div key={idx} className="hov" style={{ background:"#fff",border:`1px solid ${pkL}`,borderLeft:`4px solid ${pk}`,borderRadius:14,padding:14,marginBottom:10 }}>
                <div style={{ display:"flex",justifyContent:"space-between" }}>
                  <div style={{ flex:1 }}>
                    {prod?.fotoUrl && !isU && <img src={prod.fotoUrl} style={{ width:60,height:40,objectFit:"cover",borderRadius:8,marginBottom:6 }} onError={e => { e.target.style.display="none"; }} alt="" />}
                    <div style={{ fontWeight:800,fontSize:14,color:pk }}>{nome}</div>
                    {!isU && <div>{[it.fatias?`${it.fatias}fx (${it.formato})`:null,it.massa&&it.tipo!=="docinhos"&&it.tipo!=="bento"?it.massa:null,it.recheio1||null,it.recheio2||null].filter(Boolean).map((x, i) => <div key={i} style={{ fontSize:12,color:"#888" }}>{x}</div>)}</div>}
                    {preco != null && <div style={{ fontSize:14,fontWeight:800,color:pk,marginTop:6 }}>{fmtR(preco)}</div>}
                  </div>
                  <div style={{ display:"flex",gap:6 }}>
                    {!isU && <button onClick={() => setEditIdx(idx)} style={{ background:pkL,color:pk,border:"none",borderRadius:8,padding:"5px 10px" }}>✏️</button>}
                    <button onClick={() => setCart(p => p.filter((_, i) => i !== idx))} style={{ background:"#FEF2F2",color:"#DC2626",border:"none",borderRadius:8,padding:"5px 10px" }}>🗑</button>
                  </div>
                </div>
              </div>
            );
        })}
        {addingIt && editIdx === null
          ? <div className="fu"><ItemBuilder gAdic={cfg.adicionalGourmet} tipos={TIPOS} onSave={it => { setCart(p => san([...p, it])); setAddingIt(false); }} onCancel={() => setAddingIt(false)} /></div>
          : <button onClick={() => setAddingIt(true)} style={{ width:"100%",border:`2px dashed ${pk}`,borderRadius:14,padding:14,background:"none",color:pk,fontSize:14,fontWeight:800,marginBottom:14 }}>+ Adicionar item</button>
        }
        {cart.length > 0 && editIdx === null && !addingIt && <>
          <div style={{ background:"#fff",border:`2px solid ${pkL}`,borderRadius:14,padding:14,marginBottom:14 }}>
            {taxaReg > 0 && <div style={{ display:"flex",justifyContent:"space-between",fontSize:13,color:"#888" }}><span>Taxa</span><span>{fmtR(taxaReg)}</span></div>}
            <div style={{ display:"flex",justifyContent:"space-between",fontSize:15,fontWeight:900 }}><span>Total</span><span style={{ color:pk }}>{fmtR(cartFinal)}</span></div>
            <div style={{ display:"flex",justifyContent:"space-between",fontSize:13,color:"#BE185D",fontWeight:700 }}><span>Caução (50%)</span><span>{fmtR(cartCaucao)}</span></div>
            {cartSaldo > 0 && <div style={{ display:"flex",justifyContent:"space-between",fontSize:15,fontWeight:900,color:"#B45309",marginTop:6,background:"#FFFBEB",padding:"4px 8px",borderRadius:6 }}><span>💳 SALDO A COBRAR</span><span>{fmtR(cartSaldo)}</span></div>}
          </div>
          <Btn ch="Ver sugestões e confirmar →" onClick={() => setScreen("pedido-confirm")} />
        </>}
      </div>
    </div>
  );

  // ── CONFIRM ───────────────────────────────────────────────────
  if (screen === "pedido-confirm") return (
    <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
      <style>{CSS}</style>
      {globalModais}
      <Hdr title="📋 Confirmar pedido" onBack={() => setScreen("pedido-cart")} />
      <div style={{ padding:16,maxWidth:500,margin:"0 auto" }}>
        <Card ch={<>
          <div style={{ fontWeight:900,fontSize:16 }}>{clientUser?.nome}</div>
          <div style={{ fontSize:13,color:"#888",marginBottom:8 }}>📅 {fmtDt(pedInfo.entrega)}{pedInfo.hora ? ` às ${pedInfo.hora}` : ""} {pedInfo.regiao ? `· ${pedInfo.regiao.nome}` : ""}</div>
          {cart.map((it, i) => {
            const p    = getPrecoItem(it, cfg.adicionalGourmet);
            const isU  = it.tipo === "upsell";
            const nome = isU ? it.nome : (TIPOS.find(t => t.id === it.tipo)?.nome);
            return (
              <div key={i} style={{ borderTop:`1px solid ${pkL}`,paddingTop:8,marginTop:8 }}>
                <div style={{ display:"flex",justifyContent:"space-between",fontWeight:800,fontSize:14 }}>
                  <span>{nome}</span>
                  <span style={{ color:pk }}>{p != null ? fmtR(p) : "consultar"}</span>
                </div>
              </div>
            );
          })}
          <div style={{ borderTop:`2px solid ${pkL}`,marginTop:12,paddingTop:12 }}>
            {taxaReg > 0 && <div style={{ display:"flex",justifyContent:"space-between",fontSize:13,color:"#888" }}><span>Taxa</span><span>{fmtR(taxaReg)}</span></div>}
            <div style={{ display:"flex",justifyContent:"space-between",fontWeight:900,fontSize:15 }}><span>Total</span><span style={{ color:pk }}>{fmtR(cartFinal)}</span></div>
            <div style={{ display:"flex",justifyContent:"space-between",fontSize:13,color:"#BE185D",fontWeight:700 }}><span>Caução (50%)</span><span>{fmtR(cartCaucao)}</span></div>
            <div style={{ display:"flex",justifyContent:"space-between",fontSize:15,fontWeight:900,color:"#B45309",marginTop:6,background:"#FFFBEB",padding:"4px 8px",borderRadius:6 }}><span>💳 SALDO A COBRAR</span><span>{fmtR(cartSaldo)}</span></div>
          </div>
        </>} />
        <Btn ch="✅ Confirmar pedido" onClick={() => setUpsellOpen(true)} />
        <BtnS ch="← Editar" st={{ marginTop:8 }} onClick={() => setScreen("pedido-cart")} />
      </div>
    </div>
  );

  // ── ADMIN ─────────────────────────────────────────────────────
  if (screen === "admin") {
    // Detalhe de pedido
    if (selOrd) {
      const isEntrega   = !selOrd.regiao?.isRetirada;
      const saldoAdmin  = (selOrd.valor || 0) - (selOrd.caucao || 0);
      const urlMaps     = selOrd.endereco ? `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(selOrd.endereco)}` : null;
      return (
        <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
          <style>{CSS}</style>
          {globalModais}
          <Hdr title="Detalhes" onBack={() => setSelOrdId(null)} />
          <div style={{ padding:16,maxWidth:520,margin:"0 auto" }}>
            <Card ch={<>
              <div style={{ fontWeight:900,fontSize:17 }}>{selOrd.nome}</div>
              <div style={{ fontSize:13,color:"#888" }}>{selOrd.telefone}</div>
              {selOrd.endereco && <div style={{ fontSize:12 }}>📍 {selOrd.endereco}</div>}
              <div style={{ fontSize:13,color:"#555",marginBottom:6 }}>📅 {fmtDt(selOrd.entrega)} · {selOrd.regiao?.nome}</div>
              <StatusBar status={selOrd.status} />
              <div style={{ marginTop:4 }}><Badge s={selOrd.status} /></div>
              <div style={{ fontSize:11,color:"#9CA3AF",fontFamily:"monospace",marginTop:4 }}>🔒 {selOrd.checksum}</div>
              {selOrd.itens?.map((it, i) => {
                const p   = getPrecoItem(it, cfg.adicionalGourmet);
                const isU = it.tipo === "upsell";
                const nm  = isU ? it.nome : (TIPOS.find(t => t.id === it.tipo)?.nome);
                return (
                  <div key={i} style={{ background:"#FDF6FB",borderRadius:10,padding:"10px 12px",marginBottom:8 }}>
                    <div style={{ fontWeight:800,color:pk }}>{nm}</div>
                    {p != null && <div>{fmtR(p)}</div>}
                  </div>
                );
              })}
              <div style={{ borderTop:`2px solid ${pkL}`,paddingTop:10 }}>
                <div style={{ fontWeight:900 }}>Total: {selOrd.valor ? fmtR(selOrd.valor) : "?"}</div>
                <div style={{ color:"#BE185D" }}>Caução: {selOrd.caucao ? fmtR(selOrd.caucao) : "—"}</div>
                {saldoAdmin != null && isSinalPago(selOrd.status) && <div style={{ fontWeight:900,color:"#B45309" }}>💳 SALDO: {fmtR(saldoAdmin)}</div>}
              </div>
            </>} />

            {/* Gestão de frete */}
            {isEntrega && (
              <Card ch={<>
                <div style={{ fontWeight:800,marginBottom:8 }}>🚚 Gestão de Frete</div>
                <Fld label="Valor do Frete (R$)">
                  <input type="number" min="0" step="0.01" value={selOrd.freteManual || 0} onChange={e => updateOrd(selOrd.id, { freteManual:Number(e.target.value) })} style={fs} />
                </Fld>
              </>} />
            )}

            {/* Status */}
            <Card ch={<>
              <label style={{ fontSize:13,fontWeight:700 }}>Atualizar Status:</label>
              <div style={{ display:"flex",flexWrap:"wrap",gap:6,marginTop:6 }}>
                {STATUS_UNICO.map(st => (
                  <button key={st} style={{ background:selOrd.status===st?pk:"#F3E6F0",color:selOrd.status===st?"#fff":"#6B4C7A",border:"none",borderRadius:20,padding:"6px 12px",fontSize:11,fontWeight:700 }} onClick={() => updateOrd(selOrd.id, { status:st })}>
                    {STATUS_META[st]?.em} {st}
                  </button>
                ))}
              </div>
            </>} />

            {/* Ações */}
            {isEntrega && urlMaps && (
              <a href={urlMaps} target="_blank" rel="noreferrer" style={{ display:"block",marginBottom:8,textDecoration:"none" }}>
                <button style={{ width:"100%",background:"#EFF6FF",color:"#1D4ED8",border:"1.5px solid #BFDBFE",borderRadius:12,padding:11,fontSize:14,fontWeight:700 }}>📍 Ver Rota no Google Maps</button>
              </a>
            )}
            {isSinalPago(selOrd.status) && selOrd.valor && selOrd.telefone && (
              <a href={`https://wa.me/${selOrd.telefone?.replace(/\D/g,"")}?text=${encodeURIComponent(`Saldo restante: ${fmtR(saldoAdmin)}`)}`} target="_blank" rel="noreferrer" style={{ display:"block",marginBottom:8 }}>
                <button style={{ width:"100%",background:"#FFF7ED",color:"#B45309",border:"1.5px solid #FDE68A",borderRadius:12,padding:11,fontWeight:700 }}>💳 Cobrar Saldo ({fmtR(saldoAdmin)})</button>
              </a>
            )}
            <button onClick={() => setLabelOrd(san(selOrd))} style={{ width:"100%",background:"#EFF6FF",color:"#1D4ED8",border:"1.5px solid #BFDBFE",borderRadius:12,padding:11,fontWeight:700,marginBottom:8 }}>🏷️ Etiqueta / Recibo</button>
            <button style={{ width:"100%",background:"#FEF2F2",color:"#DC2626",border:"none",borderRadius:12,padding:12,fontWeight:700 }} onClick={() => setPinDlg({ msg:"Excluir pedido?", onOk:() => { removeOrd(selOrd.id); setSelOrdId(null); } })}>🗑 Excluir</button>
          </div>
        </div>
      );
    }

    // Lista de clientes
    if (showClts) return (
      <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
        <style>{CSS}</style>
        <Hdr title="👥 Clientes" onBack={() => setShowClts(false)} />
        <div style={{ padding:16,maxWidth:520,margin:"0 auto" }}>
          {clients.map(c => (
            <div key={c.id} style={{ background:"#fff",border:`1px solid ${pkL}`,borderRadius:14,padding:14,marginBottom:10 }}>
              <div style={{ fontWeight:900 }}>{c.nome}</div>
              <div style={{ fontSize:13,color:"#888" }}>{c.telefone}</div>
              {c.aniversario && <div style={{ fontSize:12,color:"#C084B4" }}>🎂 {fmtDt(c.aniversario)}</div>}
            </div>
          ))}
        </div>
      </div>
    );

    // Painel principal admin
    return (
      <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
        <style>{CSS}</style>
        {globalModais}
        <div style={{ background:"#fff",borderBottom:`2px solid ${pkL}`,padding:"12px 16px",display:"flex",alignItems:"center",justifyContent:"space-between",position:"sticky",top:0,zIndex:30 }}>
          <div style={{ display:"flex",alignItems:"center",gap:10 }}>
            <button onClick={() => setScreen("home")} style={{ background:"none",border:"none",fontSize:18 }}>←</button>
            <span style={{ fontFamily:"'Playfair Display',serif",fontSize:17,fontWeight:700,color:pk }}>PCP Gerência</span>
          </div>
          <div style={{ display:"flex",gap:8,alignItems:"center" }}>
            {urgentes > 0 && <span style={{ background:"#DC2626",color:"#fff",borderRadius:20,padding:"2px 8px",fontSize:11,fontWeight:700 }}>⚠ {urgentes}</span>}
            <button onClick={() => setShowClts(true)} style={{ background:pkL,color:pk,border:"none",borderRadius:20,padding:"4px 12px",fontWeight:700 }}>👥 {clients.length}</button>
          </div>
        </div>

        {/* Abas */}
        <div style={{ display:"flex",overflowX:"auto",background:"#fff",borderBottom:`2px solid ${pkL}` }}>
          {[["hoje","📅 Agenda"],["caucao","💰 Caução"],["todos","📋 Todos"],["stats","📊 Stats"],["mkt","🎂 CRM"],["configs","⚙️ Config"]].map(([v, l]) => (
            <button key={v} style={{ flexShrink:0,padding:"10px 12px",border:"none",background:"none",fontSize:11,fontWeight:700,color:adminTab===v?pk:"#9CA3AF",borderBottom:adminTab===v?`3px solid ${pk}`:"3px solid transparent" }} onClick={() => setAdminTab(v)}>{l}</button>
          ))}
        </div>

        <div style={{ padding:16,maxWidth:560,margin:"0 auto" }}>

          {/* ── ABA HOJE ── */}
          {adminTab === "hoje" && <div>
            <h3 style={{ fontSize:17,fontWeight:900 }}>Hoje · {fmtDt(hoy)}</h3>
            {todayOrds.length === 0
              ? <div style={{ textAlign:"center",padding:"32px 0",color:"#C084B4" }}>📭 Sem entregas hoje</div>
              : todayOrds.map(o => (
                  <div key={o.id} className="hov" style={{ background:"#fff",border:`1px solid ${pkL}`,borderLeft:`4px solid ${STATUS_META[o.status]?.brd||pk}`,borderRadius:14,padding:14,marginBottom:8,cursor:"pointer" }} onClick={() => setSelOrdId(o.id)}>
                    <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center" }}>
                      <div>
                        <div style={{ fontWeight:900 }}>{o.nome}</div>
                        {o.hora && <div style={{ fontSize:12,color:"#888" }}>⏰ {o.hora}</div>}
                      </div>
                      <Badge s={o.status} />
                    </div>
                    <StatusBar status={o.status} />
                  </div>
                ))
            }
          </div>}

          {/* ── ABA CAUÇÃO ── */}
          {adminTab === "caucao" && <div>
            <h3>💰 Aguardando Caução</h3>
            {orders.filter(o => o.status === "Aguardando Caução").length === 0
              ? <div style={{ textAlign:"center",padding:"24px 0",color:"#C084B4" }}>✅ Nenhum pendente</div>
              : orders.filter(o => o.status === "Aguardando Caução").map(o => (
                  <Card key={o.id} ch={<>
                    <div style={{ fontWeight:900 }}>{o.nome}</div>
                    <div style={{ fontSize:13 }}>{fmtDt(o.entrega)} · {fmtR(o.valor || 0)}</div>
                    <div style={{ display:"flex",gap:8,marginTop:10 }}>
                      <button onClick={() => setSelOrdId(o.id)} style={{ flex:1,background:pkL,color:pk,border:"none",borderRadius:10,padding:10,fontWeight:700 }}>Ver detalhes</button>
                      <button onClick={() => updateOrd(o.id, { status:"Confirmado" })} style={{ flex:1,background:"#F0FDF4",color:"#15803D",border:"1px solid #BBF7D0",borderRadius:10,padding:10,fontWeight:700 }}>✅ Confirmar</button>
                    </div>
                  </>} />
                ))
            }
          </div>}

          {/* ── ABA TODOS ── */}
          {adminTab === "todos" && <div>
            <input value={adminSrch} onChange={e => setAdminSrch(e.target.value)} placeholder="🔍 Buscar por nome ou telefone..." style={{ ...fs, marginBottom:10 }} />
            <div style={{ display:"flex",gap:6,overflowX:"auto",marginBottom:12 }}>
              {["todos", ...STATUS_UNICO].map(st => (
                <button key={st} style={{ background:adminFlt===st?pk:"#fff",color:adminFlt===st?"#fff":"#6B4C7A",border:`1.5px solid ${adminFlt===st?pk:"#E5D0EE"}`,borderRadius:20,padding:"5px 12px",fontSize:11,fontWeight:700,whiteSpace:"nowrap" }} onClick={() => setAdminFlt(st)}>
                  {st === "todos" ? "Todos" : (STATUS_META[st]?.em + " " + st)}
                </button>
              ))}
            </div>
            {sortDates.length === 0
              ? <div style={{ textAlign:"center",padding:"24px 0",color:"#C084B4" }}>Nenhum resultado</div>
              : sortDates.map(dt => (
                  <div key={dt}>
                    <div style={{ fontSize:11,fontWeight:800,color:"#C084B4",marginTop:8,marginBottom:4 }}>{fmtDt(dt)}</div>
                    {byDate[dt].map(o => (
                      <div key={o.id} className="hov" style={{ background:"#fff",border:`1px solid ${pkL}`,borderLeft:`4px solid ${o.status==="Aguardando Caução"?"#F59E0B":pk}`,borderRadius:14,padding:14,marginBottom:8,cursor:"pointer" }} onClick={() => setSelOrdId(o.id)}>
                        <div style={{ display:"flex",justifyContent:"space-between" }}>
                          <span style={{ fontWeight:900 }}>{o.nome}</span>
                          <Badge s={o.status} />
                        </div>
                        <div style={{ fontSize:13,color:"#888" }}>{o.itens?.length} itens · {o.valor ? fmtR(o.valor) : "Sob consulta"}</div>
                      </div>
                    ))}
                  </div>
                ))
            }
          </div>}

          {/* ── ABA STATS — DASHBOARD REAL ── */}
          {adminTab === "stats" && <div>
            <h3 style={{ fontSize:17,fontWeight:900,marginBottom:14 }}>📊 Dashboard</h3>

            {/* Cards principais */}
            <div style={{ display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:16 }}>
              {[
                {
                  l: "Hoje", icon:"📅",
                  v: fmtR(todayOrds.filter(o => o.status !== "Cancelado").reduce((s, o) => s + Number(o.valor||0), 0)),
                  sub: `${todayOrds.filter(o=>o.status!=="Cancelado").length} pedidos`,
                  c: pk,
                },
                {
                  l: "Semana", icon:"📆",
                  v: fmtR(semOrds.reduce((s, o) => s + Number(o.valor||0), 0)),
                  sub: `${semOrds.length} pedidos`,
                  c: "#7C3AED",
                },
                {
                  l: "Mês (confirmados)", icon:"💰",
                  v: fmtR(totalMes),
                  sub: `${ordsMes.length} pedidos`,
                  c: "#0891B2",
                },
                {
                  l: "Mês (finalizados)", icon:"🚀",
                  v: fmtR(totalMesFinalizado),
                  sub: "receita recebida",
                  c: "#15803D",
                },
              ].map((x, i) => (
                <div key={i} style={{ background:"#fff",borderTop:`3px solid ${x.c}`,borderRadius:14,padding:14 }}>
                  <div style={{ fontSize:11,color:"#888",marginBottom:2 }}>{x.icon} {x.l}</div>
                  <div style={{ fontSize:16,fontWeight:900,color:x.c }}>{x.v}</div>
                  <div style={{ fontSize:10,color:"#aaa" }}>{x.sub}</div>
                </div>
              ))}
            </div>

            {/* Status breakdown */}
            <Card ch={<>
              <div style={{ fontWeight:800,marginBottom:10 }}>📋 Pedidos por Status</div>
              {STATUS_UNICO.map(st => {
                const cnt  = orders.filter(o => o.status === st).length;
                const tot  = orders.length || 1;
                const pct  = Math.round((cnt / tot) * 100);
                const meta = STATUS_META[st];
                return (
                  <div key={st} style={{ marginBottom:10 }}>
                    <div style={{ display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:3 }}>
                      <span style={{ color:meta.text,fontWeight:700 }}>{meta.em} {st}</span>
                      <span style={{ fontWeight:900 }}>{cnt} <span style={{ color:"#aaa",fontWeight:400 }}>({pct}%)</span></span>
                    </div>
                    <div style={{ background:"#F3F4F6",borderRadius:6,height:6 }}>
                      <div style={{ background:meta.text,borderRadius:6,height:6,width:`${pct}%`,transition:"width .4s" }} />
                    </div>
                  </div>
                );
              })}
            </>} />

            {/* Ag. caução urgente */}
            {urgentes > 0 && (
              <div style={{ background:"#FEF2F2",border:"1.5px solid #FECACA",borderRadius:14,padding:14 }}>
                <div style={{ fontWeight:900,color:"#DC2626",marginBottom:4 }}>⚠️ {urgentes} pedido{urgentes!==1?"s":""} atrasado{urgentes!==1?"s":""}</div>
                <div style={{ fontSize:12,color:"#DC2626" }}>Data de entrega passada e ainda não finalizado.</div>
              </div>
            )}
          </div>}

          {/* ── ABA CRM ── */}
          {adminTab === "mkt" && <div>
            <h3 style={{ fontSize:17,fontWeight:900,marginBottom:14 }}>🎂 Aniversariantes de {new Date().toLocaleString("pt-BR",{month:"long"})}</h3>
            {aniversariantes.length === 0
              ? <div style={{ textAlign:"center",padding:"24px 0",color:"#C084B4" }}>Nenhum aniversariante este mês</div>
              : aniversariantes.map(c => (
                  <div key={c.id} style={{ background:"#fff",border:`1px solid ${pkL}`,borderLeft:"4px solid #FFD700",borderRadius:14,padding:14,marginBottom:10 }}>
                    <div style={{ fontWeight:900 }}>{c.nome}</div>
                    <div style={{ fontSize:13,color:"#888" }}>{fmtDt(c.aniversario)}</div>
                    <a href={`https://wa.me/${c.telefone?.replace(/\D/g,"")}?text=${encodeURIComponent(`🎂 Feliz aniversário, ${c.nome?.split(" ")[0]}! Temos uma surpresa especial para você da ${NOME_APP}! 🌸`)}`} target="_blank" rel="noreferrer">
                      <button style={{ background:"#25D366",color:"#fff",border:"none",borderRadius:8,padding:"5px 12px",fontSize:12,fontWeight:700,marginTop:8 }}>💬 WhatsApp</button>
                    </a>
                  </div>
                ))
            }
          </div>}

          {/* ── ABA CONFIGS ── */}
          {adminTab === "configs" && <ConfigsPanel cfg={cfg} onSave={setCfg} tipos={tipos} onUpdateTipos={setTipos} />}

        </div>
      </div>
    );
  }

  return null;
}
